// Shared services data for Billing component
import { useState, useEffect } from 'react'

// Create a simple service to fetch and cache services data
export const useServicesData = () => {
  const [services, setServices] = useState([])
  const [subServices, setSubServices] = useState([])
  const [loading, setLoading] = useState(true)

  // Fetch services data
  const fetchServicesData = async () => {
    try {
      const token = localStorage.getItem('authToken')
      console.log('Fetching services with token:', token ? 'Token present' : 'No token')
      
      const response = await fetch('http://localhost:5001/api/services', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      console.log('Services API response status:', response.status)
      
      if (response.ok) {
        const data = await response.json()
        const servicesArray = Array.isArray(data) ? data : []
        setServices(servicesArray)
        // Cache to localStorage (even if empty)
        localStorage.setItem('services', JSON.stringify(servicesArray))
        console.log('Services data fetched from API:', servicesArray.length, 'items')
      } else {
        console.error('Failed to fetch services data, status:', response.status)
        const errorText = await response.text()
        console.error('Error response:', errorText)
        
        // Try to load from localStorage as fallback
        const cachedServices = localStorage.getItem('services')
        if (cachedServices) {
          try {
            const parsedData = JSON.parse(cachedServices)
            setServices(parsedData)
            console.log('Services loaded from localStorage fallback:', parsedData.length, 'items')
          } catch (parseError) {
            console.error('Error parsing cached services:', parseError)
            setServices([])
          }
        } else {
          // Set empty array if no cache available
          setServices([])
          // Use default data as final fallback
          const defaultServices = getDefaultServices()
          setServices(defaultServices)
          console.log('Using default services data:', defaultServices.length, 'items')
        }
      }
    } catch (err) {
      console.error('Error fetching services data:', err)
      
      // Try to load from localStorage as fallback
      const cachedServices = localStorage.getItem('services')
      if (cachedServices) {
        try {
          const parsedData = JSON.parse(cachedServices)
          setServices(parsedData)
          console.log('Services loaded from localStorage fallback:', parsedData.length, 'items')
        } catch (parseError) {
          console.error('Error parsing cached services:', parseError)
          setServices([])
        }
      } else {
        // Set empty array if no cache available
        setServices([])
        // Use default data as final fallback
        const defaultServices = getDefaultServices()
        setServices(defaultServices)
        console.log('Using default services data:', defaultServices.length, 'items')
      }
    }
  }

  // Fetch sub-services data
  const fetchSubServicesData = async () => {
    try {
      const token = localStorage.getItem('authToken')
      console.log('Fetching sub-services with token:', token ? 'Token present' : 'No token')
      
      const response = await fetch('http://localhost:5001/api/subservices', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      console.log('Sub-services API response status:', response.status)
      
      if (response.ok) {
        const data = await response.json()
        const subServicesArray = Array.isArray(data) ? data : []
        setSubServices(subServicesArray)
        // Cache to localStorage (even if empty)
        localStorage.setItem('subServices', JSON.stringify(subServicesArray))
        console.log('Sub-services data fetched from API:', subServicesArray.length, 'items')
      } else {
        console.error('Failed to fetch sub-services data, status:', response.status)
        const errorText = await response.text()
        console.error('Error response:', errorText)
        
        // Try to load from localStorage as fallback
        const cachedSubServices = localStorage.getItem('subServices')
        if (cachedSubServices) {
          try {
            const parsedData = JSON.parse(cachedSubServices)
            setSubServices(parsedData)
            console.log('Sub-services loaded from localStorage fallback:', parsedData.length, 'items')
          } catch (parseError) {
            console.error('Error parsing cached sub-services:', parseError)
            setSubServices([])
          }
        } else {
          // Set empty array if no cache available
          setSubServices([])
          // Use default data as final fallback
          const defaultSubServices = getDefaultSubServices()
          setSubServices(defaultSubServices)
          console.log('Using default sub-services data:', defaultSubServices.length, 'items')
        }
      }
    } catch (err) {
      console.error('Error fetching sub-services data:', err)
      
      // Try to load from localStorage as fallback
      const cachedSubServices = localStorage.getItem('subServices')
      if (cachedSubServices) {
        try {
          const parsedData = JSON.parse(cachedSubServices)
          setSubServices(parsedData)
          console.log('Sub-services loaded from localStorage fallback:', parsedData.length, 'items')
        } catch (parseError) {
          console.error('Error parsing cached sub-services:', parseError)
          setSubServices([])
        }
      } else {
        // Set empty array if no cache available
        setSubServices([])
        // Use default data as final fallback
        const defaultSubServices = getDefaultSubServices()
        setSubServices(defaultSubServices)
        console.log('Using default sub-services data:', defaultSubServices.length, 'items')
      }
    }
  }

  // Load data on component mount
  useEffect(() => {
    const loadData = async () => {
      setLoading(true)
      await Promise.all([fetchServicesData(), fetchSubServicesData()])
      setLoading(false)
    }
    loadData()
  }, [])

  // Function to get sub-services for a specific service
  const getSubServicesForService = (serviceId) => {
    if (!serviceId) return []
    
    const filteredSubServices = subServices.filter(ss => {
      // Handle both populated serviceId (object) and non-populated (string)
      if (typeof ss.serviceId === 'object') {
        return ss.serviceId._id === serviceId
      }
      return ss.serviceId === serviceId
    })
    
    console.log(`Sub-services for service ${serviceId}:`, filteredSubServices.length, 'items')
    return filteredSubServices
  }

  // Default services data for fallback
  const getDefaultServices = () => [
    { _id: '1', serviceName: 'Printing Services', isActive: true },
    { _id: '2', serviceName: 'Lamination Services', isActive: true },
    { _id: '3', serviceName: 'Binding Services', isActive: true },
    { _id: '4', serviceName: 'Scanning Services', isActive: true },
    { _id: '5', serviceName: 'Aadhaar Services', isActive: true }
  ]

  // Default sub-services data for fallback
  const getDefaultSubServices = () => [
    { _id: '1', serviceId: '1', subServiceName: 'Black & White Printing', price: 5, unit: 'page', isActive: true },
    { _id: '2', serviceId: '1', subServiceName: 'Color Printing', price: 10, unit: 'page', isActive: true },
    { _id: '3', serviceId: '2', subServiceName: 'Matte Lamination', price: 15, unit: 'sheet', isActive: true },
    { _id: '4', serviceId: '2', subServiceName: 'Glossy Lamination', price: 20, unit: 'sheet', isActive: true },
    { _id: '5', serviceId: '3', subServiceName: 'Spiral Binding', price: 25, unit: 'set', isActive: true },
    { _id: '6', serviceId: '3', subServiceName: 'Comb Binding', price: 30, unit: 'set', isActive: true },
    { _id: '7', serviceId: '4', subServiceName: 'Document Scanning', price: 3, unit: 'page', isActive: true },
    { _id: '8', serviceId: '5', subServiceName: 'Aadhaar Update', price: 200, unit: 'service', isActive: true }
  ]

  // Return data and functions
  return {
    services,
    subServices,
    loading,
    getSubServicesForService,
    refetch: () => {
      setLoading(true)
      return Promise.all([fetchServicesData(), fetchSubServicesData()]).finally(() => setLoading(false))
    },
    clearServicesCache: () => {
      localStorage.removeItem('services')
      localStorage.removeItem('subServices')
      setServices([])
      setSubServices([])
      console.log('Services cache cleared')
    }
  }
}
