import { useState, useEffect } from 'react'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import { 
  Plus, 
  Edit2, 
  Trash2, 
  Search,
  Filter,
  Calendar,
  TrendingUp,
  FileText,
  AlertTriangle,
  Wrench,
  Printer,
  BarChart3,
  RefreshCw
} from 'lucide-react'
import { readingsAPI, machinesAPI, maintenanceAPI } from '../../services/api'
import { useNavigate, useSearchParams } from 'react-router-dom'
import PrinterCard from '../../components/PrinterCard'
import MachineCountEntry from '../../components/MachineCountEntry'
import reminderService from '../../services/reminderService'

const Readings = () => {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const [readings, setReadings] = useState([])
  const [machines, setMachines] = useState([])
  const [maintenance, setMaintenance] = useState([])
  const [countAlerts, setCountAlerts] = useState([])
  const [showAlerts, setShowAlerts] = useState(false)
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editingReading, setEditingReading] = useState(null)
  const [showDailyCountModal, setShowDailyCountModal] = useState(false)
  const [searchTerm, setSearchTerm] = useState('')
  const [filterMachine, setFilterMachine] = useState('')
  const [filterStartDate, setFilterStartDate] = useState('')
  const [filterEndDate, setFilterEndDate] = useState('')

  const [formData, setFormData] = useState({
    machineId: '',
    date: format(new Date(), 'yyyy-MM-dd'),
    currentCount: '',
    remarks: ''
  })
  const [previousCount, setPreviousCount] = useState(0)
  const [calculatedPrints, setCalculatedPrints] = useState(0)

  useEffect(() => {
    fetchData()
  }, [])

  // Recalculate alerts whenever readings or maintenance data changes
  useEffect(() => {
    if (readings.length > 0 && maintenance.length > 0) {
      const alerts = calculateCountAlerts(readings, maintenance)
      setCountAlerts(alerts)
    }
  }, [readings, maintenance])

  useEffect(() => {
    const action = searchParams.get('action')
    if (action === 'add') {
      setShowModal(true)
    }
  }, [searchParams])

  const fetchData = async () => {
    try {
      const [readingsResponse, machinesResponse, maintenanceResponse] = await Promise.all([
        readingsAPI.getAll(),
        machinesAPI.getAll(),
        maintenanceAPI.getAll()
      ])
      setReadings(readingsResponse.data)
      setMachines(machinesResponse.data)
      setMaintenance(maintenanceResponse.data)
      
      // Calculate count-based alerts
      const alerts = calculateCountAlerts(readingsResponse.data, maintenanceResponse.data)
      setCountAlerts(alerts)
    } catch (error) {
      toast.error('Failed to fetch data')
      console.error('Data fetch error:', error)
    } finally {
      setLoading(false)
    }
  }

  // Calculate count-based alerts for readings
  const calculateCountAlerts = (readingsData, maintenanceData) => {
    const alerts = []
    
    console.log('=== CALCULATING ALERTS ===')
    console.log('Readings data:', readingsData)
    console.log('Maintenance data:', maintenanceData)
    
    // Get the latest reading for each machine
    const latestReadingsByMachine = {}
    readingsData.forEach(reading => {
      if (reading.machineId && reading.machineId._id && 
          (!latestReadingsByMachine[reading.machineId._id] || 
          new Date(reading.date) > new Date(latestReadingsByMachine[reading.machineId._id].date))) {
        latestReadingsByMachine[reading.machineId._id] = reading
      }
    })
    
    console.log('Latest readings by machine:', latestReadingsByMachine)

    // Check against maintenance records with reminder counts
    maintenanceData.forEach(record => {
      if (record.nextReminderCount && record.machineId._id) {
        const latestReading = latestReadingsByMachine[record.machineId._id]
        console.log(`Checking record: ${record.serviceType}, Reminder: ${record.nextReminderCount}`)
        
        if (latestReading) {
          const currentCount = latestReading.currentCount
          const reminderCount = record.nextReminderCount
          
          console.log(`Latest reading: ${currentCount}, Reminder: ${reminderCount}`)
          
          if (currentCount >= reminderCount) {
            const overCount = currentCount - reminderCount
            console.log(`ALERT: Over by ${overCount} prints`)
            alerts.push({
              _id: `count-${record._id}`,
              machineId: record.machineId,
              serviceType: record.serviceType,
              technicianName: record.technicianName,
              nextServiceDate: record.nextServiceDate,
              priority: overCount > 1000 ? 'high' : overCount > 500 ? 'medium' : 'low',
              message: `Count-based Alert: ${overCount.toLocaleString()} prints over reminder threshold`,
              currentCount: currentCount,
              reminderCount: reminderCount,
              overCount: overCount,
              alertType: 'count',
              maintenanceRecord: record,
              readingRecord: latestReading
            })
          } else if (reminderCount - currentCount <= 1000) { // Warning when approaching
            const remaining = reminderCount - currentCount
            console.log(`WARNING: ${remaining} prints remaining`)
            alerts.push({
              _id: `warning-${record._id}`,
              machineId: record.machineId,
              serviceType: record.serviceType,
              technicianName: record.technicianName,
              nextServiceDate: record.nextServiceDate,
              priority: remaining <= 100 ? 'high' : 'medium',
              message: `Warning: ${remaining.toLocaleString()} prints remaining before maintenance`,
              currentCount: currentCount,
              reminderCount: reminderCount,
              remaining: remaining,
              alertType: 'warning',
              maintenanceRecord: record,
              readingRecord: latestReading
            })
          }
        } else {
          console.log(`No latest reading found for machine: ${record.machineId.name}`)
        }
      } else {
        console.log(`No reminder count for record: ${record.serviceType}`)
      }
    })
    
    console.log(`Total alerts calculated: ${alerts.length}`)

    const sortedAlerts = alerts.sort((a, b) => {
      const priorityOrder = { high: 0, medium: 1, low: 2 }
      return priorityOrder[a.priority] - priorityOrder[b.priority]
    })
    
    console.log('Final sorted alerts:', sortedAlerts)
    return sortedAlerts
  }

  const fetchPreviousCount = async (machineId, date) => {
    if (!machineId || !date) {
      setPreviousCount(0)
      setCalculatedPrints(0)
      return
    }

    try {
      // Get readings for this machine before the selected date
      const response = await readingsAPI.getAll({ 
        machineId, 
        endDate: date 
      })
      const previousReadings = response.data
      
      if (previousReadings.length > 0) {
        // Find the most recent reading before the selected date
        const sortedReadings = previousReadings.sort((a, b) => 
          new Date(b.date) - new Date(a.date)
        )
        const mostRecent = sortedReadings[0]
        setPreviousCount(mostRecent.currentCount)
        
        // Calculate prints if current count is entered
        if (formData.currentCount) {
          const prints = formData.currentCount - mostRecent.currentCount
          setCalculatedPrints(Math.max(0, prints))
        }
      } else {
        setPreviousCount(0)
        if (formData.currentCount) {
          setCalculatedPrints(parseInt(formData.currentCount))
        }
      }
    } catch (error) {
      console.error('Error fetching previous count:', error)
      setPreviousCount(0)
      setCalculatedPrints(0)
    }
  }

  // Update calculated prints when current count changes
  const handleCurrentCountChange = (value) => {
    const count = parseInt(value) || 0
    setFormData({ ...formData, currentCount: value })
    const prints = count - previousCount
    setCalculatedPrints(Math.max(0, prints))
  }

  // Check for maintenance alerts based on current count
  const checkMaintenanceAlerts = (machineId, currentCount) => {
    if (!machineId || !currentCount) return []
    
    const machineMaintenance = maintenance.filter(record => 
      record.machineId._id === machineId && record.nextReminderCount
    )
    
    const alerts = []
    machineMaintenance.forEach(record => {
      const reminderCount = record.nextReminderCount
      
      if (currentCount >= reminderCount) {
        const overCount = currentCount - reminderCount
        alerts.push({
          type: 'over',
          priority: overCount > 1000 ? 'high' : 'medium',
          message: `Over maintenance threshold by ${overCount.toLocaleString()} prints!`,
          reminderCount,
          overCount,
          serviceType: record.serviceType
        })
      } else if (reminderCount - currentCount <= 1000) {
        const remaining = reminderCount - currentCount
        alerts.push({
          type: 'warning',
          priority: remaining <= 100 ? 'high' : 'medium',
          message: `${remaining.toLocaleString()} prints remaining before maintenance`,
          reminderCount,
          remaining,
          serviceType: record.serviceType
        })
      }
    })
    
    return alerts
  }

  // Fetch previous count when machine or date changes
  useEffect(() => {
    if (showModal && formData.machineId && formData.date) {
      fetchPreviousCount(formData.machineId, formData.date)
    }
  }, [formData.machineId, formData.date, showModal])

  const handleSubmit = async (e) => {
    e.preventDefault()
    try {
      if (editingReading) {
        await readingsAPI.update(editingReading._id, formData)
        toast.success('Reading updated successfully')
      } else {
        await readingsAPI.create(formData)
        toast.success('Reading added successfully')
      }
      fetchData()
      resetForm()
    } catch (error) {
      toast.error('Failed to save reading')
      console.error('Save reading error:', error)
    }
  }

  const handleEdit = (reading) => {
    setEditingReading(reading)
    setFormData({
      machineId: reading.machineId._id,
      date: format(new Date(reading.date), 'yyyy-MM-dd'),
      currentCount: reading.currentCount,
      remarks: reading.remarks || ''
    })
    setPreviousCount(reading.previousCount || 0)
    setCalculatedPrints(reading.totalPrints || 0)
    setShowModal(true)
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this reading?')) {
      try {
        await readingsAPI.delete(id)
        toast.success('Reading deleted successfully')
        fetchData()
      } catch (error) {
        toast.error('Failed to delete reading')
        console.error('Delete reading error:', error)
      }
    }
  }

  const resetForm = () => {
    setFormData({
      machineId: '',
      date: format(new Date(), 'yyyy-MM-dd'),
      currentCount: '',
      remarks: ''
    })
    setPreviousCount(0)
    setCalculatedPrints(0)
    setEditingReading(null)
    setShowModal(false)
  }

  const applyFilters = async () => {
    try {
      const filters = {}
      if (filterMachine) filters.machineId = filterMachine
      if (filterStartDate) filters.startDate = filterStartDate
      if (filterEndDate) filters.endDate = filterEndDate
      
      const response = await readingsAPI.getAll(filters)
      setReadings(response.data)
    } catch (error) {
      toast.error('Failed to apply filters')
      console.error('Filter error:', error)
    }
  }

  const clearFilters = () => {
    setFilterMachine('')
    setFilterStartDate('')
    setFilterEndDate('')
    fetchData()
  }

  useEffect(() => {
    applyFilters()
  }, [filterMachine, filterStartDate, filterEndDate])

  const filteredReadings = readings
    .filter(reading => {
      const matchesSearch = (reading.machineId && reading.machineId.name && reading.machineId.name.toLowerCase().includes(searchTerm.toLowerCase())) ||
                           (reading.remarks && reading.remarks.toLowerCase().includes(searchTerm.toLowerCase()))
      return matchesSearch
    })
    .sort((a, b) => {
      // First sort by date descending (newest dates first)
      const dateComparison = new Date(b.date) - new Date(a.date)
      if (dateComparison !== 0) return dateComparison
      
      // If same date, sort by creation time descending (last entry first)
      return new Date(b.createdAt) - new Date(a.createdAt)
    })

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    )
  }

  return (
    <div className="h-screen overflow-y-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Daily Readings</h2>
        <div className="flex space-x-3">
          <button
            onClick={() => {
              // Recalculate alerts before showing
              const alerts = calculateCountAlerts(readings, maintenance)
              setCountAlerts(alerts)
              setShowAlerts(!showAlerts)
            }}
            className="btn-secondary flex items-center space-x-2"
          >
            <AlertTriangle className="h-4 w-4" />
            <span>Alerts ({countAlerts.length})</span>
          </button>
          <button
            onClick={() => {
              // Manual refresh of alerts
              fetchData()
              toast.success('Alerts refreshed')
            }}
            className="btn-secondary flex items-center space-x-2"
            title="Refresh Alerts"
          >
            <RefreshCw className="h-4 w-4" />
            <span className="hidden sm:inline">Refresh</span>
          </button>
           
          <button
            onClick={() => setShowModal(true)}
            className="btn-primary flex items-center space-x-2"
          >
            <Plus className="h-4 w-4" />
            <span>Add Reading</span>
          </button>
          
          <button
            onClick={() => setShowDailyCountModal(true)}
            className="btn-secondary flex items-center space-x-2 bg-green-600 hover:bg-green-700"
          >
            <Calendar className="h-4 w-4" />
            <span>Daily Count Entry</span>
          </button>
        </div>
      </div>
          {/* Count-Based Alerts Section */}
      {showAlerts && countAlerts.length > 0 && (
        <div className="card border-l-4 border-orange-400 bg-gradient-to-r from-orange-50 to-red-50">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center">
                <AlertTriangle className="h-6 w-6 text-orange-600 mr-3" />
                <h3 className="text-xl font-bold text-orange-800">Maintenance Count Alerts</h3>
              </div>
              <div className="flex space-x-4 text-sm">
                <span className="bg-red-100 text-red-800 px-2 py-1 rounded">
                  {countAlerts.filter(a => a.priority === 'high').length} High
                </span>
                <span className="bg-yellow-100 text-yellow-800 px-2 py-1 rounded">
                  {countAlerts.filter(a => a.priority === 'medium').length} Medium
                </span>
              </div>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {countAlerts.map((alert, index) => (
                <div key={index} className={`border rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow ${
                  alert.priority === 'high' ? 'bg-red-50 border-red-200' : 
                  alert.priority === 'medium' ? 'bg-yellow-50 border-yellow-200' : 
                  'bg-blue-50 border-blue-200'
                }`}>
                  <div className="flex items-start justify-between mb-2">
                    <div className="flex items-center">
                      <span className="text-lg mr-2">📊</span>
                      <span className={`text-xs font-semibold px-2 py-1 rounded ${
                        alert.alertType === 'count' ? 'bg-red-100 text-red-800' : 'bg-orange-100 text-orange-800'
                      }`}>
                        {alert.alertType === 'count' ? 'Over Threshold' : 'Warning'}
                      </span>
                    </div>
                    <span className={`text-xs font-bold px-2 py-1 rounded ${
                      alert.priority === 'high' ? 'bg-red-100 text-red-800' : 
                      alert.priority === 'medium' ? 'bg-yellow-100 text-yellow-800' : 
                      'bg-green-100 text-green-800'
                    }`}>
                      {alert.priority.toUpperCase()}
                    </span>
                  </div>
                  
                  <div className="mb-3">
                    <p className="font-bold text-gray-900">{alert.machineId.name}</p>
                    <p className="text-sm text-gray-600">{alert.machineId.brand}</p>
                    <p className="text-sm opacity-75">{alert.serviceType}</p>
                  </div>
                  
                  <div className="text-sm">
                    <p className="font-semibold text-gray-800">{alert.message}</p>
                    <div className="mt-2 p-2 bg-white/50 rounded text-xs">
                      <div className="flex justify-between">
                        <span>Current Count:</span>
                        <span className="font-bold">{alert.currentCount?.toLocaleString()}</span>
                      </div>
                      <div className="flex justify-between">
                        <span>Reminder Count:</span>
                        <span className="font-bold">{alert.reminderCount?.toLocaleString()}</span>
                      </div>
                      {alert.overCount && (
                        <div className="flex justify-between text-red-600 font-bold">
                          <span>Over by:</span>
                          <span>{alert.overCount.toLocaleString()}</span>
                        </div>
                      )}
                      {alert.remaining && (
                        <div className="flex justify-between text-orange-600 font-bold">
                          <span>Remaining:</span>
                          <span>{alert.remaining.toLocaleString()}</span>
                        </div>
                      )}
                    </div>
                    <div className="mt-2 text-xs text-gray-500">
                      Latest Reading: {format(new Date(alert.readingRecord.date), 'MMM dd, yyyy')}
                    </div>
                  </div>
                  
                  <div className="mt-3 pt-3 border-t border-gray-200">
                    <p className="text-xs text-gray-500">
                      Technician: {alert.technicianName}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Printer Cards Section */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
            <Printer className="h-5 w-5 text-gray-600" />
            Printer Status Overview
          </h3>
          <button
            onClick={() => navigate('/machines')}
            className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center gap-1"
          >
            View All Machines
            <BarChart3 className="h-4 w-4" />
          </button>
        </div>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {machines.slice(0, 8).map(machine => (
            <PrinterCard 
              key={machine._id} 
              machineId={machine._id}
              showDetails={false}
            />
          ))}
        </div>
        
        {machines.length > 8 && (
          <div className="mt-4 text-center">
            <button
              onClick={() => navigate('/machines')}
              className="text-sm text-blue-600 hover:text-blue-700 font-medium"
            >
              View all {machines.length} machines
            </button>
          </div>
        )}
      </div>

      {/* Filters */}
      <div className="card">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search readings..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              />
            </div>
          </div>
          
          <div>
            <select
              value={filterMachine}
              onChange={(e) => setFilterMachine(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="">All Machines</option>
              {machines.map(machine => (
                <option key={machine._id} value={machine._id}>
                  {machine.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <input
              type="date"
              value={filterStartDate}
              onChange={(e) => setFilterStartDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              placeholder="Start Date"
            />
          </div>

          <div>
            <input
              type="date"
              value={filterEndDate}
              onChange={(e) => setFilterEndDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              placeholder="End Date"
            />
          </div>
        </div>
        
        {(filterMachine || filterStartDate || filterEndDate) && (
          <div className="mt-4">
            <button
              onClick={clearFilters}
              className="text-sm text-primary-600 hover:text-primary-800"
            >
              Clear Filters
            </button>
          </div>
        )}
      </div>

      {/* Readings Table */}
      <div className="card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky-header">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Date
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Machine
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Previous Count
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Current Count
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Total Prints
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Remarks
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200 table-zebra">
              {filteredReadings.length > 0 ? (
                filteredReadings.map((reading) => (
                  <tr key={reading._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div className="flex items-center">
                        <Calendar className="h-4 w-4 text-gray-400 mr-2" />
                        {format(new Date(reading.date), 'MMM dd, yyyy')}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div>
                        <div className="font-medium">{reading.machineId.name}</div>
                        <div className="text-xs text-gray-500">{reading.machineId.brand} - {reading.machineId.modelNumber}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {reading.previousCount.toLocaleString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {reading.currentCount.toLocaleString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm">
                      <div className="flex items-center">
                        <TrendingUp className="h-4 w-4 text-green-500 mr-2" />
                        <span className="font-medium text-green-600">
                          {reading.totalPrints.toLocaleString()}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {reading.remarks || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex space-x-2">
                        <button
                          onClick={() => handleEdit(reading)}
                          className="text-primary-600 hover:text-primary-900"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(reading._id)}
                          className="text-red-600 hover:text-red-900"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="7" className="px-6 py-4 text-center text-gray-500">
                    No readings found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-full max-w-4xl shadow-lg rounded-md bg-white">
            <h3 className="text-lg font-bold text-gray-900 mb-4">
              {editingReading ? 'Edit Reading' : 'Add New Reading'}
            </h3>
            
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Machine
                  </label>
                  <select
                    required
                    value={formData.machineId}
                    onChange={(e) => setFormData({ ...formData, machineId: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  >
                    <option value="">Select Machine</option>
                    {machines.map(machine => (
                      <option key={machine._id} value={machine._id}>
                        {machine.name} ({machine.brand})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Date
                  </label>
                  <input
                    type="date"
                    required
                    value={formData.date}
                    onChange={(e) => {
                      const selectedDate = new Date(e.target.value)
                      const today = new Date()
                      today.setHours(0, 0, 0, 0) // Set to start of day for comparison
                      
                      if (selectedDate > today) {
                        toast.error('Future dates are not allowed for readings')
                        return // Don't update the form data
                      }
                      
                      setFormData({ ...formData, date: e.target.value })
                    }}
                    max={format(new Date(), 'yyyy-MM-dd')}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Current Count
                  </label>
                  <input
                    type="number"
                    required
                    min="0"
                    value={formData.currentCount}
                    onChange={(e) => handleCurrentCountChange(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                    placeholder="Enter current meter reading"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Remark
                  </label>
                  <textarea
                    value={formData.remarks}
                    onChange={(e) => setFormData({ ...formData, remarks: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                    rows="3"
                    placeholder="Any additional notes..."
                  />
                </div>
              </div>

              {/* Maintenance Alerts for Current Count */}
              {formData.currentCount && formData.machineId && (
                <div>
                  {(() => {
                    const alerts = checkMaintenanceAlerts(formData.machineId, parseInt(formData.currentCount))
                    if (alerts.length === 0) return null
                    
                    return (
                      <div className="space-y-2">
                        {alerts.map((alert, index) => (
                          <div key={index} className={`p-3 rounded-lg border ${
                            alert.priority === 'high' 
                              ? 'bg-red-50 border-red-200 text-red-800' 
                              : 'bg-orange-50 border-orange-200 text-orange-800'
                          }`}>
                            <div className="flex items-start">
                              <AlertTriangle className="h-5 w-5 mr-2 flex-shrink-0 mt-0.5" />
                              <div>
                                <p className="font-semibold text-sm">{alert.message}</p>
                                <div className="text-xs mt-1 space-y-1">
                                  <div>Maintenance: {alert.serviceType}</div>
                                  <div>Reminder Count: {alert.reminderCount.toLocaleString()}</div>
                                  {alert.overCount && (
                                    <div className="font-bold">Over by: {alert.overCount.toLocaleString()} prints</div>
                                  )}
                                  {alert.remaining && (
                                    <div>Remaining: {alert.remaining.toLocaleString()} prints</div>
                                  )}
                                </div>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    )
                  })()}
                </div>
              )}

              {/* Previous Count and Calculated Prints Display */}
              {(formData.machineId && formData.date) && (
                <div className="bg-gray-50 p-4 rounded-lg">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm font-medium text-gray-600">Previous Count</p>
                      <p className="text-lg font-semibold text-gray-900">
                        {previousCount.toLocaleString()}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm font-medium text-gray-600">Calculated Prints</p>
                      <p className="text-lg font-semibold text-green-600">
                        {calculatedPrints.toLocaleString()}
                      </p>
                    </div>
                  </div>
                  <div className="mt-2 text-xs text-gray-500">
                    Total Prints = Current Count - Previous Count
                  </div>
                </div>
              )}

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={resetForm}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn-primary"
                >
                  {editingReading ? 'Update' : 'Add'} Reading
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
      
      {/* Daily Count Entry Modal */}
      {showDailyCountModal && (
        <MachineCountEntry
          onClose={() => setShowDailyCountModal(false)}
          onSave={(readingsData) => {
            // Refresh data after saving
            fetchData()
            toast.success('Daily counts saved successfully!')
          }}
        />
      )}
    </div>
  )
}

export default Readings
