import React, { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Lock, 
  Eye, 
  EyeOff, 
  AlertTriangle, 
  CheckCircle, 
  X,
  Shield,
  Key
} from 'lucide-react'

const PinVerification = ({ onVerified, onCancel, title = 'Enter PIN to Access Settings' }) => {
  const [pin, setPin] = useState('')
  const [showPin, setShowPin] = useState(false)
  const [isVerifying, setIsVerifying] = useState(false)
  const [attempts, setAttempts] = useState(0)
  const [isLocked, setIsLocked] = useState(false)
  const [lockTimeRemaining, setLockTimeRemaining] = useState(0)

  // Check lock status on mount
  useEffect(() => {
    const lockTime = localStorage.getItem('pinLockTime')
    const storedAttempts = localStorage.getItem('pinAttempts')
    
    if (storedAttempts) {
      setAttempts(parseInt(storedAttempts))
    }
    
    if (lockTime) {
      const lockEndTime = new Date(lockTime).getTime()
      const currentTime = new Date().getTime()
      
      if (currentTime < lockEndTime) {
        setIsLocked(true)
        setLockTimeRemaining(Math.ceil((lockEndTime - currentTime) / 1000 / 60))
        
        // Update countdown
        const interval = setInterval(() => {
          const remaining = Math.ceil((lockEndTime - new Date().getTime()) / 1000 / 60)
          if (remaining <= 0) {
            setIsLocked(false)
            setLockTimeRemaining(0)
            localStorage.removeItem('pinLockTime')
            localStorage.removeItem('pinAttempts')
            clearInterval(interval)
          } else {
            setLockTimeRemaining(remaining)
          }
        }, 60000)
        
        return () => clearInterval(interval)
      } else {
        localStorage.removeItem('pinLockTime')
        localStorage.removeItem('pinAttempts')
      }
    }
  }, [])

  // Handle PIN verification
  const handleVerify = async () => {
    if (isLocked) {
      toast.error(`PIN verification is locked. Try again in ${lockTimeRemaining} minutes.`)
      return
    }

    if (!pin) {
      toast.error('Please enter your PIN')
      return
    }

    setIsVerifying(true)

    try {
      // Simulate verification process
      await new Promise(resolve => setTimeout(resolve, 500))

      const storedPin = localStorage.getItem('appSecurityPin')
      
      if (pin === storedPin) {
        // Success - reset attempts
        localStorage.removeItem('pinAttempts')
        localStorage.removeItem('pinLockTime')
        toast.success('PIN verified successfully')
        onVerified()
      } else {
        // Failed attempt
        handleFailedAttempt()
      }
    } catch (error) {
      console.error('PIN verification error:', error)
      toast.error('Verification failed. Please try again.')
    } finally {
      setIsVerifying(false)
    }
  }

  // Handle failed attempt
  const handleFailedAttempt = () => {
    const newAttempts = attempts + 1
    setAttempts(newAttempts)
    localStorage.setItem('pinAttempts', newAttempts.toString())

    if (newAttempts >= 3) {
      const lockTime = new Date(Date.now() + 15 * 60 * 1000) // 15 minutes
      localStorage.setItem('pinLockTime', lockTime.toISOString())
      setIsLocked(true)
      setLockTimeRemaining(15)
      toast.error('Too many failed attempts. PIN verification locked for 15 minutes.')
      setPin('')
    } else {
      const remaining = 3 - newAttempts
      toast.error(`Incorrect PIN. ${remaining} attempts remaining.`)
      setPin('')
    }
  }

  // Handle keyboard input
  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleVerify()
    }
  }

  // PIN input buttons for mobile
  const handleNumberClick = (number) => {
    if (pin.length < 4) {
      setPin(prev => prev + number)
    }
  }

  const handleClear = () => {
    setPin('')
  }

  const handleBackspace = () => {
    setPin(prev => prev.slice(0, -1))
  }

  return (
    <div className="fixed inset-0 bg-black bg-opacity-70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-xs transform transition-all duration-300 scale-100">
        {/* Header */}
        <div className="bg-gradient-to-r from-blue-600 via-purple-600 to-indigo-600 text-white p-3 rounded-t-2xl relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-r from-blue-600/20 to-purple-600/20 animate-pulse"></div>
          <div className="relative flex items-center justify-between">
            <div className="flex items-center">
              <div className="bg-white/20 p-1.5 rounded-full backdrop-blur-sm mr-2">
                <Shield className="h-4 w-4 text-white" />
              </div>
              <div>
                <h3 className="text-base font-bold">{title}</h3>
              </div>
            </div>
            <button
              onClick={onCancel}
              className="text-white/80 hover:text-white hover:bg-white/20 p-1 rounded-full transition-all duration-200"
            >
              <X className="h-4 w-4" />
            </button>
          </div>
        </div>

        {/* PIN Input */}
        <div className="p-3">
          {/* PIN Display */}
          <div className="mb-4">
            <div className="flex justify-center space-x-2">
              {[...Array(4)].map((_, index) => (
                <div
                  key={index}
                  className={`relative w-8 h-8 rounded-full border-2 flex items-center justify-center text-sm font-bold transition-all duration-300 transform ${
                    pin[index] 
                      ? 'border-blue-500 bg-gradient-to-br from-blue-50 to-purple-50 text-blue-600 scale-105 shadow-lg' 
                      : 'border-gray-300 bg-gray-50 hover:border-gray-400'
                  }`}
                >
                  {pin[index] && (
                    <div className="absolute inset-0 bg-gradient-to-br from-blue-500/10 to-purple-500/10 rounded-full animate-pulse"></div>
                  )}
                  <span className="relative z-10">
                    {showPin ? pin[index] : pin[index] ? '●' : ''}
                  </span>
                </div>
              ))}
            </div>
            
            {/* Show/Hide PIN */}
            <div className="flex justify-center mt-2">
              <button
                onClick={() => setShowPin(!showPin)}
                className="flex items-center px-2 py-1 text-xs text-gray-600 hover:text-gray-800 hover:bg-gray-100 rounded-full transition-all duration-200"
              >
                {showPin ? <EyeOff className="h-3 w-3 mr-1" /> : <Eye className="h-3 w-3 mr-1" />}
              </button>
            </div>
          </div>

          {/* Lock Status */}
          {isLocked && (
            <div className="mb-4 p-2 bg-red-50 border border-red-200 rounded-lg">
              <div className="flex items-center">
                <div className="bg-red-100 p-1 rounded-full mr-2">
                  <Lock className="h-3 w-3 text-red-600" />
                </div>
                <div>
                  <p className="text-red-800 font-semibold text-xs">PIN Locked</p>
                  <p className="text-red-600 text-xs">
                    {lockTimeRemaining} min{lockTimeRemaining !== 1 ? 's' : ''}
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Attempts Remaining */}
          {!isLocked && attempts > 0 && (
            <div className="mb-4 p-2 bg-yellow-50 border border-yellow-200 rounded-lg">
              <div className="flex items-center">
                <div className="bg-yellow-100 p-1 rounded-full mr-2">
                  <AlertTriangle className="h-3 w-3 text-yellow-600" />
                </div>
                <p className="text-yellow-800 text-xs font-medium">
                  {3 - attempts} left
                </p>
              </div>
            </div>
          )}

          {/* Number Pad (Vibrant Color Scheme) */}
          <div className="grid grid-cols-3 gap-2 mb-4">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(number => (
              <button
                key={number}
                onClick={() => handleNumberClick(number.toString())}
                disabled={isLocked || isVerifying}
                className="group relative w-12 h-12 bg-gradient-to-br from-blue-500 via-blue-600 to-indigo-600 hover:from-blue-400 hover:via-blue-500 hover:to-indigo-500 rounded-xl text-lg font-bold text-white disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl border border-blue-400 hover:border-blue-300 mx-auto overflow-hidden"
              >
                <div className="absolute inset-0 bg-gradient-to-br from-cyan-400/0 to-teal-400/0 group-hover:from-cyan-400/30 group-hover:to-teal-400/30 rounded-xl transition-all duration-300"></div>
                <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                <div className="absolute inset-0 bg-gradient-to-t from-white/10 to-transparent rounded-xl"></div>
                <span className="relative z-10 drop-shadow-md">{number}</span>
              </button>
            ))}
            <button
              onClick={handleClear}
              disabled={isLocked || isVerifying}
              className="group relative w-12 h-12 bg-gradient-to-br from-pink-500 via-rose-500 to-red-500 hover:from-pink-400 hover:via-rose-400 hover:to-red-400 rounded-xl text-sm font-bold text-white disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl border border-pink-400 hover:border-pink-300 mx-auto overflow-hidden"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-white/0 to-white/30 group-hover:from-white/20 group-hover:to-white/40 rounded-xl transition-all duration-300"></div>
              <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
              <div className="absolute inset-0 bg-gradient-to-t from-white/10 to-transparent rounded-xl"></div>
              <span className="relative z-10 drop-shadow-md">Clr</span>
            </button>
            <button
              onClick={() => handleNumberClick('0')}
              disabled={isLocked || isVerifying}
              className="group relative w-12 h-12 bg-gradient-to-br from-blue-500 via-blue-600 to-indigo-600 hover:from-blue-400 hover:via-blue-500 hover:to-indigo-500 rounded-xl text-lg font-bold text-white disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl border border-blue-400 hover:border-blue-300 mx-auto overflow-hidden"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-cyan-400/0 to-teal-400/0 group-hover:from-cyan-400/30 group-hover:to-teal-400/30 rounded-xl transition-all duration-300"></div>
              <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
              <div className="absolute inset-0 bg-gradient-to-t from-white/10 to-transparent rounded-xl"></div>
              <span className="relative z-10 drop-shadow-md">0</span>
            </button>
            <button
              onClick={handleBackspace}
              disabled={isLocked || isVerifying}
              className="group relative w-12 h-12 bg-gradient-to-br from-emerald-500 via-green-500 to-teal-500 hover:from-emerald-400 hover:via-green-400 hover:to-teal-400 rounded-xl text-sm font-bold text-white disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl border border-emerald-400 hover:border-emerald-300 mx-auto overflow-hidden"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-white/0 to-white/30 group-hover:from-white/20 group-hover:to-white/40 rounded-xl transition-all duration-300"></div>
              <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
              <div className="absolute inset-0 bg-gradient-to-t from-white/10 to-transparent rounded-xl"></div>
              <span className="relative z-10 drop-shadow-md">←</span>
            </button>
          </div>

          {/* Action Buttons (Small Round Design) */}
          <div className="flex space-x-2">
            <button
              onClick={onCancel}
              disabled={isVerifying}
              className="group relative flex-1 px-3 py-2 bg-gradient-to-br from-white via-gray-50 to-gray-100 hover:from-gray-100 hover:to-gray-200 rounded-full text-gray-700 disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-200 transform hover:scale-105 active:scale-95 shadow-md hover:shadow-lg border border-gray-300 hover:border-gray-500 font-bold text-xs"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-gray-500/0 to-gray-600/0 group-hover:from-gray-500/5 group-hover:to-gray-600/5 rounded-full transition-all duration-200"></div>
              <span className="relative z-10">Cancel</span>
            </button>
            <button
              onClick={handleVerify}
              disabled={isLocked || isVerifying || !pin}
              className="group relative flex-1 px-3 py-2 bg-gradient-to-br from-blue-600 via-purple-600 to-indigo-600 hover:from-blue-700 hover:to-purple-700 rounded-full text-white disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-200 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl border border-blue-500 hover:border-blue-400 font-bold text-xs"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-white/0 to-white/20 group-hover:from-white/10 group-hover:to-white/30 rounded-full transition-all duration-200"></div>
              <div className="relative z-10 flex items-center justify-center">
                {isVerifying ? (
                  <>
                    <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-white mr-1"></div>
                  </>
                ) : (
                  <>
                    <Key className="h-3 w-3 mr-1" />
                    Verify
                  </>
                )}
              </div>
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

export default PinVerification
