import React, { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  AlertTriangle, 
  Database, 
  Printer, 
  Calendar, 
  CheckCircle, 
  X, 
  Clock,
  RefreshCw,
  Settings,
  TrendingUp,
  Activity
} from 'lucide-react'
import { machinesAPI } from '../services/api'
import reminderService from '../services/reminderService'

const ReminderSystem = () => {
  const [showBackupReminder, setShowBackupReminder] = useState(false)
  const [showMachineCountReminder, setShowMachineCountReminder] = useState(false)
  const [lastBackupDate, setLastBackupDate] = useState(null)
  const [lastMachineCountDate, setLastMachineCountDate] = useState(null)
  const [todayMachineCount, setTodayMachineCount] = useState(0)
  const [isLoading, setIsLoading] = useState(false)

  // Initialize reminder service and check reminders on component mount
  useEffect(() => {
    reminderService.init()
    reminderService.resetDailyMachineCounts()
    
    // Check reminders after a short delay to allow for proper initialization
    const timer = setTimeout(() => {
      checkBackupReminder()
      checkMachineCountReminder()
    }, 1000)
    
    return () => clearTimeout(timer)
  }, [])

  // Check if backup reminder should be shown (every 2 days)
  const checkBackupReminder = () => {
    if (reminderService.shouldShowReminder('backup')) {
      const stats = reminderService.getReminderStats()
      const daysSinceBackup = stats.backup.daysSinceLastBackup
      
      if (daysSinceBackup !== null) {
        setLastBackupDate(new Date(Date.now() - daysSinceBackup * 24 * 60 * 60 * 1000).toISOString().split('T')[0])
      }
      
      setShowBackupReminder(true)
    }
  }

  // Check if machine count reminder should be shown (daily)
  const checkMachineCountReminder = async () => {
    if (reminderService.shouldShowReminder('machineCount')) {
      try {
        setIsLoading(true)
        const response = await machinesAPI.getAll()
        const machines = response.data || []
        
        const stats = reminderService.getReminderStats()
        const stored = localStorage.getItem('lastMachineCountDate')
        
        if (!stats.machineCount.hasTodayCounts) {
          setLastMachineCountDate(stored)
          setTodayMachineCount(machines.length)
          setShowMachineCountReminder(true)
        }
      } catch (error) {
        console.error('Error checking machine count reminder:', error)
      } finally {
        setIsLoading(false)
      }
    }
  }

  // Handle backup reminder dismissal
  const handleBackupReminderDismiss = (action) => {
    reminderService.showReminder('backup', action)
    
    if (action === 'backup') {
      // Navigate to backup settings
      window.location.href = '/settings?tab=site-backup'
    } else if (action === 'remind-later') {
      toast.info('Will remind you again in 4 hours')
    } else if (action === 'dismiss') {
      toast.info('Backup reminder dismissed. Next reminder in 2 days.')
    }
    
    setShowBackupReminder(false)
  }

  // Handle machine count reminder dismissal
  const handleMachineCountReminderDismiss = (action) => {
    reminderService.showReminder('machineCount', action)
    
    if (action === 'enter-counts') {
      // Navigate to machines readings page
      window.location.href = '/machines?tab=readings'
      toast.success('Great! Keep tracking your machine usage.')
    } else if (action === 'skip-today') {
      reminderService.markMachineCountsEntered()
      toast.info('Machine count reminder skipped for today.')
    }
    
    setShowMachineCountReminder(false)
  }

  // Check if it's the first visit of the day
  const isFirstVisitToday = () => {
    const lastVisit = localStorage.getItem('lastVisitDate')
    const today = new Date().toISOString().split('T')[0]
    
    if (lastVisit !== today) {
      localStorage.setItem('lastVisitDate', today)
      return true
    }
    return false
  }

  return (
    <>
      {/* Backup Reminder Modal */}
      {showBackupReminder && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-2xl max-w-md w-full">
            <div className="bg-gradient-to-r from-orange-500 to-red-500 text-white p-6 rounded-t-lg">
              <div className="flex items-center justify-between">
                <div className="flex items-center">
                  <Database className="h-6 w-6 mr-3" />
                  <h3 className="text-lg font-semibold">Backup Reminder</h3>
                </div>
                <button
                  onClick={() => handleBackupReminderDismiss('dismiss')}
                  className="text-white hover:text-gray-200 transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>
            
            <div className="p-6">
              <div className="flex items-center mb-4">
                <AlertTriangle className="h-8 w-8 text-orange-500 mr-3" />
                <div>
                  <p className="text-gray-800 font-medium">
                    {lastBackupDate ? 
                      `It's been ${Math.floor((new Date() - new Date(lastBackupDate)) / (1000 * 60 * 60 * 24))} days since your last backup` :
                      'No backup records found'
                    }
                  </p>
                  <p className="text-sm text-gray-600 mt-1">
                    Regular backups help protect your important data from loss
                  </p>
                </div>
              </div>
              
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 mb-6">
                <h4 className="text-sm font-semibold text-blue-900 mb-2">Backup Benefits:</h4>
                <ul className="text-sm text-blue-800 space-y-1">
                  <li>· Protect against data loss</li>
                  <li>· Quick disaster recovery</li>
                  <li>· Peace of mind for your business</li>
                </ul>
              </div>
              
              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={() => handleBackupReminderDismiss('backup')}
                  className="flex-1 bg-orange-600 text-white px-4 py-2 rounded-lg hover:bg-orange-700 transition-colors flex items-center justify-center"
                >
                  <Database className="h-4 w-4 mr-2" />
                  Backup Now
                </button>
                <button
                  onClick={() => handleBackupReminderDismiss('remind-later')}
                  className="flex-1 bg-gray-200 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-300 transition-colors flex items-center justify-center"
                >
                  <Clock className="h-4 w-4 mr-2" />
                  Remind Later
                </button>
                <button
                  onClick={() => handleBackupReminderDismiss('dismiss')}
                  className="flex-1 bg-gray-100 text-gray-600 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors"
                >
                  Dismiss
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Machine Count Reminder Modal */}
      {showMachineCountReminder && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-2xl max-w-md w-full">
            <div className="bg-gradient-to-r from-blue-500 to-indigo-500 text-white p-6 rounded-t-lg">
              <div className="flex items-center justify-between">
                <div className="flex items-center">
                  <Printer className="h-6 w-6 mr-3" />
                  <h3 className="text-lg font-semibold">Daily Machine Count Entry</h3>
                </div>
                <button
                  onClick={() => handleMachineCountReminderDismiss('dismiss')}
                  className="text-white hover:text-gray-200 transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>
            
            <div className="p-6">
              <div className="flex items-center mb-4">
                <Calendar className="h-8 w-8 text-blue-500 mr-3" />
                <div>
                  <p className="text-gray-800 font-medium">
                    Good morning! Time to record today's machine readings
                  </p>
                  <p className="text-sm text-gray-600 mt-1">
                    You have {todayMachineCount} machines to check today
                  </p>
                </div>
              </div>
              
              <div className="bg-green-50 border border-green-200 rounded-lg p-3 mb-6">
                <h4 className="text-sm font-semibold text-green-900 mb-2">Why Daily Counts Matter:</h4>
                <ul className="text-sm text-green-800 space-y-1">
                  <li>· Track machine usage patterns</li>
                  <li>· Schedule maintenance proactively</li>
                  <li>· Monitor business performance</li>
                  <li>· Prevent unexpected downtime</li>
                </ul>
              </div>
              
              {isLoading ? (
                <div className="flex items-center justify-center py-4">
                  <RefreshCw className="h-6 w-6 animate-spin text-blue-500 mr-2" />
                  <span className="text-gray-600">Loading machine data...</span>
                </div>
              ) : (
                <div className="flex flex-col sm:flex-row gap-3">
                  <button
                    onClick={() => handleMachineCountReminderDismiss('enter-counts')}
                    className="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center"
                  >
                    <Printer className="h-4 w-4 mr-2" />
                    Enter Counts
                  </button>
                  <button
                    onClick={() => handleMachineCountReminderDismiss('dismiss')}
                    className="flex-1 bg-gray-200 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-300 transition-colors"
                  >
                    Skip Today
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  )
}

export default ReminderSystem
