import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Shield, AlertTriangle } from 'lucide-react'
import { toast } from 'react-hot-toast'

const AdminGuard = ({ children, fallbackPath = '/dashboard' }) => {
  const [isLoading, setIsLoading] = useState(true)
  const [isAdmin, setIsAdmin] = useState(false)
  const navigate = useNavigate()

  useEffect(() => {
    const checkAdminAccess = () => {
      try {
        const user = localStorage.getItem('user')
        
        if (user) {
          const parsedUser = JSON.parse(user)
          console.log('Checking admin access for user:', parsedUser)
          
          // Check if user is admin
          const hasAdminRole = parsedUser.role === 'admin'
          const hasAdminPermissions = parsedUser.permissions?.settings === true
          
          if (hasAdminRole || hasAdminPermissions) {
            setIsAdmin(true)
            console.log('Admin access granted')
          } else {
            setIsAdmin(false)
            console.log('Admin access denied - insufficient permissions')
            toast.error('Access denied. Admin privileges required.')
            navigate(fallbackPath)
          }
        } else {
          setIsAdmin(false)
          console.log('No user found, redirecting to login')
          navigate('/login')
        }
      } catch (error) {
        console.error('Error checking admin access:', error)
        setIsAdmin(false)
        navigate('/login')
      }
      
      setIsLoading(false)
    }

    checkAdminAccess()
  }, [navigate, fallbackPath])

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl shadow-lg shadow-blue-500/30 mb-4">
            <Shield className="w-8 h-8 text-white" />
          </div>
          <p className="text-gray-600">Checking admin permissions...</p>
        </div>
      </div>
    )
  }

  if (!isAdmin) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-red-50 via-orange-50 to-yellow-50 flex items-center justify-center">
        <div className="text-center p-8">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-red-500 to-orange-600 rounded-2xl shadow-lg shadow-red-500/30 mb-4">
            <AlertTriangle className="w-8 h-8 text-white" />
          </div>
          <h2 className="text-2xl font-bold text-red-800 mb-2">Access Denied</h2>
          <p className="text-red-600 mb-6">You need administrator privileges to access this page.</p>
          <button
            onClick={() => navigate(fallbackPath)}
            className="px-6 py-3 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
          >
            Go Back
          </button>
        </div>
      </div>
    )
  }

  return children
}

export default AdminGuard
