import React, { useState, useEffect, useRef } from 'react'
import { Download, Printer, Filter, DollarSign, TrendingUp, TrendingDown, FileText, Calendar, ArrowUpRight, ArrowDownRight } from 'lucide-react'
import { expensesAPI, expenseCategoriesAPI, expenseSubCategoriesAPI, billsAPI } from '../services/api'
import { toast } from 'react-hot-toast'
import jsPDF from 'jspdf'
import 'jspdf-autotable'

const Reports = () => {
  const [expenses, setExpenses] = useState([])
  const [bills, setBills] = useState([])
  const [categories, setCategories] = useState([])
  const [subCategories, setSubCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [dateRange, setDateRange] = useState({
    startDate: new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0]
  })
  const [selectedCategory, setSelectedCategory] = useState('')
  const [selectedSubCategory, setSelectedSubCategory] = useState('')
  const reportRef = useRef(null)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [expensesRes, billsRes, categoriesRes] = await Promise.all([
        expensesAPI.getAll(),
        billsAPI.getAll(),
        expenseCategoriesAPI.getAll()
      ])
      
      setExpenses(expensesRes?.data || [])
      setBills(billsRes?.data || [])
      setCategories(Array.isArray(categoriesRes?.data) ? categoriesRes.data : [])
    } catch (error) {
      console.error('Error fetching data:', error)
      toast.error('Failed to load report data')
    } finally {
      setLoading(false)
    }
  }

  const fetchSubCategories = async (categoryId) => {
    if (!categoryId) {
      setSubCategories([])
      return
    }
    try {
      const response = await expenseSubCategoriesAPI.getAll(categoryId)
      setSubCategories(Array.isArray(response?.data) ? response.data : [])
    } catch (error) {
      console.error('Error fetching subcategories:', error)
      setSubCategories([])
    }
  }

  useEffect(() => {
    fetchSubCategories(selectedCategory)
  }, [selectedCategory])

  const getFilteredData = () => {
    let filteredExpenses = expenses
    let filteredBills = bills

    // Filter by date range
    if (dateRange.startDate) {
      filteredExpenses = filteredExpenses.filter(expense => 
        new Date(expense.date) >= new Date(dateRange.startDate)
      )
      filteredBills = filteredBills.filter(bill => 
        new Date(bill.billDate || bill.createdAt) >= new Date(dateRange.startDate)
      )
    }
    if (dateRange.endDate) {
      filteredExpenses = filteredExpenses.filter(expense => 
        new Date(expense.date) <= new Date(dateRange.endDate)
      )
      filteredBills = filteredBills.filter(bill => 
        new Date(bill.billDate || bill.createdAt) <= new Date(dateRange.endDate)
      )
    }

    // Filter by category
    if (selectedCategory) {
      filteredExpenses = filteredExpenses.filter(expense => 
        expense.category === selectedCategory
      )
    }

    // Filter by subcategory
    if (selectedSubCategory) {
      filteredExpenses = filteredExpenses.filter(expense => 
        expense.subCategory === selectedSubCategory
      )
    }

    return { filteredExpenses, filteredBills }
  }

  const getTotalIncome = () => {
    const { filteredBills } = getFilteredData()
    return filteredBills.reduce((total, bill) => total + (bill.totalAmount || bill.grandTotal || 0), 0)
  }

  const getTotalExpenses = () => {
    const { filteredExpenses } = getFilteredData()
    return filteredExpenses.reduce((total, expense) => total + (expense.amount || 0), 0)
  }

  const getNetProfit = () => {
    return getTotalIncome() - getTotalExpenses()
  }

  const getExpensesByCategory = () => {
    const { filteredExpenses } = getFilteredData()
    const grouped = {}
    filteredExpenses.forEach(expense => {
      const category = expense.category || 'Uncategorized'
      grouped[category] = (grouped[category] || 0) + (expense.amount || 0)
    })
    return Object.entries(grouped).map(([categoryId, amount]) => {
      const categoryData = categories.find(c => c._id === categoryId)
      return {
        categoryId,
        categoryName: categoryData?.name || categoryId,
        amount,
        count: filteredExpenses.filter(e => e.category === categoryId).length
      }
    }).sort((a, b) => b.amount - a.amount)
  }

  const getExpensesBySubCategory = () => {
    const { filteredExpenses } = getFilteredData()
    const grouped = {}
    filteredExpenses.forEach(expense => {
      if (expense.subCategory) {
        const subCategory = expense.subCategory
        grouped[subCategory] = (grouped[subCategory] || 0) + (expense.amount || 0)
      }
    })
    return Object.entries(grouped).map(([subCategoryId, amount]) => {
      const subCategoryData = subCategories.find(sc => sc._id === subCategoryId)
      return {
        subCategoryId,
        subCategoryName: subCategoryData?.name || subCategoryId,
        amount,
        count: filteredExpenses.filter(e => e.subCategory === subCategoryId).length
      }
    }).sort((a, b) => b.amount - a.amount)
  }

  const handlePrint = () => {
    const printContent = reportRef.current
    const printWindow = window.open('', '_blank')
    printWindow.document.write(`
      <html>
        <head>
          <title>Financial Reports</title>
          <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            h1 { color: #333; border-bottom: 2px solid #333; padding-bottom: 10px; }
            h2 { color: #666; margin-top: 30px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; }
            th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
            th { background-color: #f5f5f5; font-weight: bold; }
            .summary { background-color: #f9f9f9; padding: 15px; border-radius: 5px; margin: 20px 0; }
            .summary-item { display: flex; justify-content: space-between; margin: 5px 0; }
            .total { font-weight: bold; font-size: 18px; color: #333; }
          </style>
        </head>
        <body>
          ${printContent.innerHTML}
        </body>
      </html>
    `)
    printWindow.document.close()
    printWindow.print()
  }

  const handlePDFExport = () => {
    const doc = new jsPDF()
    const pageWidth = doc.internal.pageSize.width
    
    // Title
    doc.setFontSize(20)
    doc.text('Financial Reports', pageWidth / 2, 20, { align: 'center' })
    
    // Date range
    doc.setFontSize(12)
    doc.text(`Period: ${dateRange.startDate} to ${dateRange.endDate}`, pageWidth / 2, 30, { align: 'center' })
    
    // Summary
    doc.setFontSize(14)
    doc.text('Summary', 20, 50)
    
    doc.setFontSize(11)
    doc.text(`Total Income: $${getTotalIncome().toFixed(2)}`, 20, 60)
    doc.text(`Total Expenses: $${getTotalExpenses().toFixed(2)}`, 20, 70)
    doc.text(`Net Profit: $${getNetProfit().toFixed(2)}`, 20, 80)
    
    // Expenses by category table
    const categoryData = getExpensesByCategory().map(item => [
      item.categoryName,
      item.count.toString(),
      `$${item.amount.toFixed(2)}`
    ])
    
    doc.autoTable({
      head: [['Category', 'Count', 'Amount']],
      body: categoryData,
      startY: 90,
      theme: 'grid',
      styles: { fontSize: 10 },
      headStyles: { fillColor: [66, 139, 202] }
    })
    
    // Expenses by subcategory table
    const subCategoryData = getExpensesBySubCategory().map(item => [
      item.subCategoryName,
      item.count.toString(),
      `$${item.amount.toFixed(2)}`
    ])
    
    doc.autoTable({
      head: [['Sub Category', 'Count', 'Amount']],
      body: subCategoryData,
      startY: doc.lastAutoTable.finalY + 20,
      theme: 'grid',
      styles: { fontSize: 10 },
      headStyles: { fillColor: [76, 175, 80] }
    })
    
    doc.save(`financial-report-${new Date().toISOString().split('T')[0]}.pdf`)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Financial Reports</h1>
          <p className="text-gray-600 mt-1">Generate income, expense and subcategory-wise reports</p>
        </div>
        <div className="flex space-x-3">
          <button
            onClick={handlePrint}
            className="px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors flex items-center space-x-2"
          >
            <Printer className="h-4 w-4" />
            <span>Print</span>
          </button>
          <button
            onClick={handlePDFExport}
            className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors flex items-center space-x-2"
          >
            <Download className="h-4 w-4" />
            <span>Export PDF</span>
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="flex items-center mb-4">
          <Filter className="h-5 w-5 text-gray-500 mr-2" />
          <h3 className="text-lg font-semibold text-gray-900">Filters</h3>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
            <input
              type="date"
              value={dateRange.startDate}
              onChange={(e) => setDateRange(prev => ({ ...prev, startDate: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
            <input
              type="date"
              value={dateRange.endDate}
              onChange={(e) => setDateRange(prev => ({ ...prev, endDate: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
            <select
              value={selectedCategory}
              onChange={(e) => {
                setSelectedCategory(e.target.value)
                setSelectedSubCategory('')
              }}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="">All Categories</option>
              {categories.map(category => (
                <option key={category._id} value={category._id}>
                  {category.name}
                </option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Sub Category</label>
            <select
              value={selectedSubCategory}
              onChange={(e) => setSelectedSubCategory(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              disabled={!selectedCategory}
            >
              <option value="">All Sub Categories</option>
              {subCategories.map(subCategory => (
                <option key={subCategory._id} value={subCategory._id}>
                  {subCategory.name}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Report Content */}
      <div ref={reportRef} className="space-y-6">
        {/* Summary Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total Income</p>
                <p className="text-2xl font-bold text-green-600">${getTotalIncome().toFixed(2)}</p>
              </div>
              <ArrowUpRight className="h-8 w-8 text-green-600" />
            </div>
          </div>
          
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total Expenses</p>
                <p className="text-2xl font-bold text-red-600">${getTotalExpenses().toFixed(2)}</p>
              </div>
              <ArrowDownRight className="h-8 w-8 text-red-600" />
            </div>
          </div>
          
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Net Profit</p>
                <p className={`text-2xl font-bold ${getNetProfit() >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  ${getNetProfit().toFixed(2)}
                </p>
              </div>
              <DollarSign className={`h-8 w-8 ${getNetProfit() >= 0 ? 'text-green-600' : 'text-red-600'}`} />
            </div>
          </div>
          
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Profit Margin</p>
                <p className={`text-2xl font-bold ${getNetProfit() >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  {getTotalIncome() > 0 ? ((getNetProfit() / getTotalIncome()) * 100).toFixed(1) : 0}%
                </p>
              </div>
              <TrendingUp className={`h-8 w-8 ${getNetProfit() >= 0 ? 'text-green-600' : 'text-red-600'}`} />
            </div>
          </div>
        </div>

        {/* Expenses by Category */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Expenses by Category</h3>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Count</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Percentage</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {getExpensesByCategory().map((item, index) => (
                  <tr key={index}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.categoryName}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.count}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      ${item.amount.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {getTotalExpenses() > 0 ? ((item.amount / getTotalExpenses()) * 100).toFixed(1) : 0}%
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Expenses by Sub Category */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Expenses by Sub Category</h3>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sub Category</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Count</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Percentage</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {getExpensesBySubCategory().map((item, index) => (
                  <tr key={index}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.subCategoryName}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.count}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      ${item.amount.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {getTotalExpenses() > 0 ? ((item.amount / getTotalExpenses()) * 100).toFixed(1) : 0}%
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Reports
