/**
 * Utility functions for currency formatting
 */

/**
 * Formats a number into Indian Rupee format
 * @param {number} amount - The amount to format
 * @returns {string} Formatted currency string with ₹ symbol
 */
export const formatCurrency = (amount) => {
  if (amount === null || amount === undefined || isNaN(amount)) {
    return '₹0';
  }

  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  }).format(amount);
};

/**
 * Formats a number into Indian Rupee format without currency symbol
 * @param {number} amount - The amount to format
 * @returns {string} Formatted number string
 */
export const formatNumber = (amount) => {
  if (amount === null || amount === undefined || isNaN(amount)) {
    return '0';
  }

  return new Intl.NumberFormat('en-IN', {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  }).format(amount);
};

/**
 * Parses a formatted currency string back to number
 * @param {string} formattedAmount - The formatted currency string
 * @returns {number} Parsed number
 */
export const parseCurrency = (formattedAmount) => {
  if (!formattedAmount || typeof formattedAmount !== 'string') {
    return 0;
  }
  
  // Remove currency symbol and commas, then parse
  const cleanAmount = formattedAmount.replace(/[₹,]/g, '');
  const parsed = parseFloat(cleanAmount);
  
  return isNaN(parsed) ? 0 : parsed;
};
